// Minimal reconstruction of alloy-sol-type-parser's identifier type.

pub fn is_valid_identifier(s: &str) -> bool {
    let mut chars = s.chars();
    match chars.next() {
        Some(c) if c == '_' || c.is_ascii_alphabetic() => {}
        _ => return false,
    }
    chars.all(|c| c == '_' || c.is_ascii_alphanumeric())
}

pub struct Ident<'a>(&'a str);

impl<'a> Ident<'a> {
    // Faithful reproduction of the target function: the only precondition
    // check is a debug_assert!, which is compiled out / skipped whenever
    // the caller doesn't hit it (e.g. release builds, or any safe wrapper
    // that doesn't fully validate before calling this).
    pub const unsafe fn new_unchecked(s: &'a str) -> Self {
        debug_assert!(is_valid_identifier(s));
        Self(s)
    }

    // Public SAFE constructor, mirroring how real crates wrap `new_unchecked`
    // behind a validating API. The bug: it only checks non-emptiness instead
    // of the full identifier grammar (ASCII alnum/underscore), so it still
    // calls new_unchecked with a value that violates the real invariant.
    pub fn new(s: &'a str) -> Self {
        assert!(!s.is_empty(), "identifier must not be empty");
        unsafe { Self::new_unchecked(s) }
    }

    // Downstream code trusts the identifier invariant (ASCII-only content,
    // so byte offset 1 is always a char boundary) and uses get_unchecked
    // to skip the first byte without a UTF-8 boundary check.
    pub fn without_first_char(&self) -> &str {
        unsafe { self.0.get_unchecked(1..) }
    }
}

