fn main() {
    // "\u{e9}" ("e" with acute accent) is a 2-byte UTF-8 codepoint.
    // It passes the incomplete `Ident::new` check (non-empty) even though
    // it is not a valid ASCII identifier per `is_valid_identifier`.
    let ident = poc_lib::Ident::new("\u{e9}");

    // Slicing at byte offset 1 lands in the middle of the 2-byte codepoint,
    // producing a &str whose bytes are not valid UTF-8 -- undefined behavior,
    // reached entirely through safe function calls in main.
    let bad = ident.without_first_char();
    println!("{}", bad);
}

