// Minimal reconstruction of bit-struct's generated wrapper type.
// bit-struct wraps a small integer and exposes `new_unchecked` as the raw
// unsafe constructor used internally by safe-looking builder APIs. The
// invariant it must uphold: the stored u8 must be a valid discriminant
// for `Kind` (0 or 1 only). `new_unchecked` performs NO validation.

#[repr(u8)]
#[derive(Debug, Clone, Copy)]
pub enum Kind {
    A = 0,
    B = 1,
}

#[repr(transparent)]
#[derive(Clone, Copy)]
pub struct Wrapper(u8);

impl Wrapper {
    // Mirrors the target function exactly: no precondition check before
    // trusting `value` as a valid encoding.
    pub const unsafe fn new_unchecked(value: u8) -> Self {
        Self(value)
    }

    // Safe-looking public API (no `unsafe` at call site) that misuses
    // new_unchecked internally with an out-of-range value derived from
    // ordinary safe input, exactly like bit-struct's safe setters do
    // internally when composed carelessly.
    pub fn from_raw_safe_api(value: u8) -> Self {
        // No range check performed here either -- this is the "missing
        // precondition check" bridging safe code to the unsafe op.
        unsafe { Self::new_unchecked(value) }
    }

    // Interprets the stored bits as the enum, as bit-struct's field
    // accessors do via transmute for enum-backed fields.
    pub fn as_kind(self) -> Kind {
        unsafe { core::mem::transmute::<u8, Kind>(self.0) }
    }
}

poc_main_rs:
fn main() {
    // Purely safe Rust: no `unsafe` keyword appears in this file.
    // 42 is not a valid Kind discriminant (only 0 or 1 are valid),
    // but the public safe API happily constructs it.
    let w = poc_lib::Wrapper::from_raw_safe_api(42);

    // Reading it back as Kind reaches an invalid enum discriminant: UB.
    let k = w.as_kind();
    println!("{:?}", k);
}

