use std::cell::RefCell;
use std::ffi::CStr;
use std::os::raw::{c_char, c_int};

thread_local! {
    pub static PROBES: RefCell<Vec<USDTProbe>> = RefCell::new(Vec::new());
}

#[derive(Debug)]
pub struct USDTProbe {
    pub binary: String,
    pub handler: String,
    pub address: u64,
    pub pid: Option<c_int>,
}

/// # Safety mirror of the real bcc callback: it assumes `bin_path` and `fn_name`
/// are valid, live, NUL-terminated C strings supplied by the C library.
unsafe extern "C" fn uprobe_foreach_cb(
    bin_path: *const c_char,
    fn_name: *const c_char,
    address: u64,
    pid: c_int,
) {
    PROBES.with(|probes| {
        let binary = CStr::from_ptr(bin_path).to_str().map(|s| s.to_owned()).ok();
        let handler = CStr::from_ptr(fn_name).to_str().map(|s| s.to_owned()).ok();

        if let Some(binary) = binary {
            if let Some(handler) = handler {
                probes.borrow_mut().push(USDTProbe {
                    binary,
                    handler,
                    address,
                    pid: Some(pid),
                });
            }
        }
    })
}

/// Safe public wrapper, analogous to how bcc's USDTContext exposes probe
/// enumeration to safe callers: it does not validate that the pointers it
/// forwards to the C-ABI callback are non-null or point to live, NUL-terminated
/// data. In the real crate this pointer originates from libbcc; here we let
/// the safe caller supply it, exposing the same missing-validation gap.
pub fn run_foreach(bin_path: *const c_char, fn_name: *const c_char, address: u64, pid: c_int) {
    unsafe {
        uprobe_foreach_cb(bin_path, fn_name, address, pid);
    }
}

pub fn probe_count() -> usize {
    PROBES.with(|probes| probes.borrow().len())
}

poc_main_rs:
fn main() {
    // Safe Rust: no `unsafe` keyword here at all. We simply never had a
    // valid C string to hand the wrapper (e.g. this mirrors a libbcc
    // callback firing with a null/dangling name pointer), and the safe
    // API happily forwards it into CStr::from_ptr.
    let bin_path: *const std::os::raw::c_char = std::ptr::null();
    let fn_name: *const std::os::raw::c_char = std::ptr::null();

    poc_lib::run_foreach(bin_path, fn_name, 0x1000, 42);

    println!("probes recorded: {}", poc_lib::probe_count());
}

