use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicU8, Ordering};

const LOCKED_BIT: u8 = 1;

/// Minimal reconstruction of parking_lot_core's raw word lock.
pub struct RawLock {
    state: AtomicU8,
}

impl RawLock {
    pub fn new() -> Self {
        RawLock { state: AtomicU8::new(0) }
    }

    pub fn try_lock(&self) -> bool {
        self.state
            .compare_exchange(0, LOCKED_BIT, Ordering::Acquire, Ordering::Relaxed)
            .is_ok()
    }

    pub fn lock(&self) {
        while !self.try_lock() {
            std::hint::spin_loop();
        }
    }

    /// Same shape/semantics as parking_lot_core's WordLock::unlock:
    /// unconditionally clears the LOCKED_BIT with Release ordering.
    /// No check that the caller is the current owner.
    pub unsafe fn unlock(&self) {
        let _state = self.state.fetch_sub(LOCKED_BIT, Ordering::Release);
    }
}

pub struct SharedCell<T> {
    lock: RawLock,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for SharedCell<T> {}

impl<T> SharedCell<T> {
    pub fn new(v: T) -> Self {
        SharedCell { lock: RawLock::new(), data: UnsafeCell::new(v) }
    }

    pub fn lock(&self) -> Guard<'_, T> {
        self.lock.lock();
        Guard { cell: self }
    }

    /// SAFE public wrapper around the unsafe raw unlock -- this is the
    /// modular-unsafe-function bug: it lets safe code release a lock it
    /// does not own, with no way to know whether another guard is live.
    pub fn force_unlock(&self) {
        unsafe {
            self.lock.unlock();
        }
    }
}

pub struct Guard<'a, T> {
    cell: &'a SharedCell<T>,
}

impl<'a, T> std::ops::Deref for Guard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.cell.data.get() }
    }
}

impl<'a, T> std::ops::DerefMut for Guard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.cell.data.get() }
    }
}

impl<'a, T> Drop for Guard<'a, T> {
    fn drop(&mut self) {
        unsafe {
            self.cell.lock.unlock();
        }
    }
}

