#![forbid(unsafe_code)]

use poc::SharedCell;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let cell = Arc::new(SharedCell::new(0i64));
    let c2 = cell.clone();

    let h = thread::spawn(move || {
        let mut guard = c2.lock();
        for i in 0..1_000_000i64 {
            *guard = i;
        }
        thread::sleep(Duration::from_millis(200));
    });

    thread::sleep(Duration::from_millis(50));

    // Safe call: releases the lock even though `h`'s guard is still alive.
    cell.force_unlock();

    // Lock "succeeds" again concurrently with the still-live guard in `h`.
    let mut guard2 = cell.lock();
    for i in 0..1_000_000i64 {
        *guard2 = i * 2; // unsynchronized concurrent access with thread h
    }

    h.join().unwrap();
}

