use std::alloc::{alloc, Layout};
use std::mem::MaybeUninit;
use std::ptr::NonNull;

#[repr(C)]
pub struct Pair<H, T> {
    pub header: H,
    pub value: T,
}

pub struct HeaderSlice<H, T> {
    ptr: NonNull<Pair<H, MaybeUninit<T>>>,
    len: usize,
    cap: usize,
}

impl<H, T> HeaderSlice<H, T> {
    /// Safety (as documented upstream): caller must ensure `ptr` points to a valid
    /// allocation of `cap` `Pair<H, MaybeUninit<T>>` slots, of which the first `len`
    /// slots have their `value` field initialized. This function performs no such
    /// check itself.
    pub unsafe fn from_raw_parts(
        ptr: NonNull<Pair<H, MaybeUninit<T>>>,
        len: usize,
        cap: usize,
    ) -> Self {
        Self { ptr, len, cap }
    }

    pub fn len(&self) -> usize {
        self.len
    }

    /// Safe accessor: trusts `len` as the count of initialized elements,
    /// exactly as the real crate's slice-producing methods do.
    pub fn values(&self) -> &[T] {
        unsafe {
            std::slice::from_raw_parts(self.ptr.as_ptr() as *const T, self.len)
        }
    }
}

/// Safe, allocation-only constructor: allocates `cap` uninitialized slots and
/// reports `len` slots as "ready", without writing anything.
/// Mirrors a common safe-looking helper built on top of `from_raw_parts`.
/// No `unsafe` keyword needed at any call site.
pub fn make_uninit_slice<H: Default, T>(len: usize, cap: usize) -> HeaderSlice<H, T> {
    assert!(len <= cap);
    let layout = Layout::array::<Pair<H, MaybeUninit<T>>>(cap.max(1)).unwrap();
    let raw = unsafe { alloc(layout) } as *mut Pair<H, MaybeUninit<T>>;
    let ptr = NonNull::new(raw).expect("allocation failed");
    // SAFETY (violated): only the allocation for `cap` slots is guaranteed here;
    // none of the `len` slots have actually been initialized. This wrapper itself
    // is safe (no `unsafe` at its call sites), yet it hands out `len` as if the
    // values were initialized, breaking the invariant `from_raw_parts` relies on.
    unsafe { HeaderSlice::from_raw_parts(ptr, len, cap) }
}

poc_main_rs:
use poc_lib::make_uninit_slice;

fn main() {
    // Purely safe code: no `unsafe` block anywhere in this file.
    let hs = make_uninit_slice::<(), i32>(4, 8);
    let values: &[i32] = hs.values();
    println!("len = {}", hs.len());
    // Reading uninitialized memory through a safe slice reference.
    println!("value[0] = {}", values[0]);
}

