pub unsafe fn fast_program(&mut self, from: *const u64, to: *mut u64) -> Result<(), Error> {
    let sr: u32 = self.sr();
    if sr & flags::BSY != 0 {
        return Err(Error::Busy);
    }
    if sr & flags::PESD != 0 {
        return Err(Error::Suspend);
    }

    self.clear_all_err();

    c1_c2!(
        self.flash.cr.modify(|_, w| w.fstpg().set_bit()),
        self.flash.c2cr.modify(|_, w| w.fstpg().set_bit())
    );

    let from: *const u32 = from as *const u32;
    let to: *mut u32 = to as *mut u32;

    (0..64)
        .into_iter()
        .for_each(|word| unsafe { write_volatile(to.offset(word), from.offset(word).read()) });

    let ret: Result<(), Error> = self.wait_for_not_busy();

    c1_c2!(
        self.flash.cr.modify(|_, w| w.fstpg().clear_bit()),
        self.flash.c2cr.modify(|_, w| w.fstpg().clear_bit())
    );

    ret
}

poc_lib_rs:
use std::ptr::write_volatile;

pub const BSY: u32 = 1 << 0;
pub const PESD: u32 = 1 << 1;

#[derive(Debug)]
pub enum Error {
    Busy,
    Suspend,
}

// Minimal stand-in for the svd2rust FLASH peripheral register block.
pub struct Flash {
    sr: u32,
}

impl Flash {
    pub fn new() -> Self {
        Flash { sr: 0 }
    }

    fn sr(&self) -> u32 {
        self.sr
    }

    fn clear_all_err(&mut self) {}

    fn wait_for_not_busy(&mut self) -> Result<(), Error> {
        Ok(())
    }

    // Mirrors stm32wlxx-hal's `fast_program`: no validation that `to` lies in
    // flash / that the 64-word (256-byte) window at `from`/`to` is in bounds.
    // The `unsafe` keyword only gates the raw pointer arithmetic inside; the
    // *public entry point* below is safe, so nothing stops a safe caller from
    // handing in undersized buffers.
    pub unsafe fn fast_program(&mut self, from: *const u64, to: *mut u64) -> Result<(), Error> {
        let sr: u32 = self.sr();
        if sr & BSY != 0 {
            return Err(Error::Busy);
        }
        if sr & PESD != 0 {
            return Err(Error::Suspend);
        }

        self.clear_all_err();

        let from: *const u32 = from as *const u32;
        let to: *mut u32 = to as *mut u32;

        (0..64)
            .into_iter()
            .for_each(|word| unsafe { write_volatile(to.offset(word), from.offset(word).read()) });

        self.wait_for_not_busy()
    }

    // Safe wrapper as would appear in a higher-level HAL API: it forwards
    // ordinary references/slices into the unsafe routine without checking
    // that they cover the full 256-byte (64 x u32) programming window that
    // fast_program unconditionally reads and writes.
    pub fn program_words(&mut self, src: &[u64], dst: &mut [u64]) -> Result<(), Error> {
        let from = src.as_ptr();
        let to = dst.as_mut_ptr();
        unsafe { self.fast_program(from, to) }
    }
}

poc_main_rs:
use poc_lib::Flash;

fn main() {
    let mut flash = Flash::new();

    // Only 4 u64 words (32 bytes) allocated, but fast_program always copies
    // 64 u32 words (256 bytes) starting here -> out-of-bounds volatile
    // read and write, all reached through 100% safe code.
    let src: [u64; 4] = [0xAAAA_AAAA_AAAA_AAAA; 4];
    let mut dst: [u64; 4] = [0; 4];

    flash.program_words(&src, &mut dst).unwrap();

    println!("dst = {:?}", dst);
}

