use std::ptr;

/// Minimal stand-in for the svd2rust-generated register writer proxy `W`.
pub struct W {
    pub bits: u16,
    pub reg: *mut u16,
}

/// Field-writer proxy, mirrors the generated `_W` field accessor type.
pub struct FieldW<'a> {
    pub w: &'a mut W,
}

impl<'a> FieldW<'a> {
    /// Mirrors imxrt1062-enc1's generated `bits(self, value: u8)`.
    /// Body semantics kept identical: mask+shift into a 5-bit field at offset 8,
    /// no validation that `value` is a hardware-defined valid encoding.
    pub unsafe fn bits(self, value: u8) -> &'a mut W {
        self.w.bits = (self.w.bits & !(0x1f << 8)) | (((value as u16) & 0x1f) << 8);
        self.w
    }
}

impl W {
    pub fn field(&mut self) -> FieldW<'_> {
        FieldW { w: self }
    }

    /// Commits the shadow value to the "device" register via a volatile write.
    /// This is the safe, public surface an svd2rust `write(|w| ...)` closure exposes;
    /// internally it calls the `unsafe fn bits` above, but no `unsafe` is required
    /// at the call site because the crate wraps it for the user.
    pub fn commit(&mut self) {
        unsafe { ptr::write_volatile(self.reg, self.bits) }
    }
}

pub struct RegisterBlock {
    pub reg: *mut u16,
}

impl RegisterBlock {
    /// Safe public entry point, analogous to svd2rust's `reg.write(|w| w.field().bits(v))`.
    pub fn write<F>(&mut self, f: F)
    where
        F: FnOnce(FieldW) -> &mut W,
    {
        let mut w = W { bits: 0, reg: self.reg };
        f(w.field());
        w.commit();
    }
}

poc_main_rs:
use poc::RegisterBlock;

fn main() {
    // No hardware mapped: the register points at an unmapped MMIO address.
    let mut reg = RegisterBlock { reg: 0x4000_0000 as *mut u16 };

    // Fully safe call site: no `unsafe` keyword here, yet the library's
    // `bits()` writes a raw, unchecked 5-bit field value straight to the
    // "device" register via a volatile write to an unmapped address.
    reg.write(|w| w.bits(0x1f));
}

