use std::alloc::{alloc_zeroed, Layout};
use std::slice;

pub struct Extent {
    pub width: u32,
    pub height: u32,
}

pub struct GpuInner {
    pub extent: Extent,
    pub format: u32,
}

pub struct Gpu {
    inner: GpuInner,
}

impl Gpu {
    // Safe constructor: nothing stops a caller from passing a 0x0 extent,
    // mirroring a swapchain that hasn't been sized/created yet.
    pub fn new(width: u32, height: u32, format: u32) -> Self {
        Gpu {
            inner: GpuInner {
                extent: Extent { width, height },
                format,
            },
        }
    }

    pub fn get(&self) -> &GpuInner {
        &self.inner
    }
}

pub struct Image {
    ptr: *mut u8,
    len: usize,
}

impl Image {
    // Mirrors the real Image::new: computes a byte size straight from the
    // requested width/height with no non-zero check before allocating.
    fn new(_vulkan: &Gpu, width: u32, height: u32, _format: u32) -> Self {
        let len = (width as usize) * (height as usize) * 4;
        let layout = Layout::from_size_align(len, 4).unwrap();
        // SAFETY (assumed by this module): callers only ever request
        // non-zero-extent images. That invariant is never checked.
        let ptr = unsafe { alloc_zeroed(layout) };
        Image { ptr, len }
    }

    pub fn as_slice(&self) -> &[u8] {
        unsafe { slice::from_raw_parts(self.ptr, self.len) }
    }
}

// Same body/semantics as the real asi_vulkan::create_ms_buffer, exposed as a
// safe function: it just reads the Gpu's current extent/format and builds an
// Image from them, trusting the extent is non-zero.
pub fn create_ms_buffer(vulkan: &Gpu) -> Image {
    let extent_w = vulkan.get().extent.width;
    let extent_h = vulkan.get().extent.height;
    let format = vulkan.get().format;
    Image::new(vulkan, extent_w, extent_h, format)
}

