poc_lib_rs:
use std::cell::UnsafeCell;
use std::ops::{Deref, DerefMut};
use std::sync::atomic::{AtomicUsize, Ordering};

const SHARED: usize = 1;
const EXCLUSIVE: usize = 1 << (usize::BITS - 1);

pub struct RawLock {
    lock: AtomicUsize,
}

impl RawLock {
    pub fn new() -> Self {
        RawLock { lock: AtomicUsize::new(0) }
    }

    pub fn is_locked_shared(&self) -> bool {
        self.lock.load(Ordering::Relaxed) & !EXCLUSIVE != 0
    }

    pub fn try_lock_shared(&self) -> bool {
        let mut cur = self.lock.load(Ordering::Relaxed);
        loop {
            if cur & EXCLUSIVE != 0 {
                return false;
            }
            match self.lock.compare_exchange_weak(
                cur,
                cur + SHARED,
                Ordering::Acquire,
                Ordering::Relaxed,
            ) {
                Ok(_) => return true,
                Err(v) => cur = v,
            }
        }
    }

    pub fn try_lock_exclusive(&self) -> bool {
        self.lock
            .compare_exchange(0, EXCLUSIVE, Ordering::Acquire, Ordering::Acquire)
            .is_ok()
    }

    pub fn unlock_exclusive(&self) {
        self.lock.fetch_and(!EXCLUSIVE, Ordering::Release);
    }

    // === target function, semantics kept verbatim from one-shot-mutex ===
    unsafe fn unlock_shared(&self) {
        debug_assert!(self.is_locked_shared());
        self.lock.fetch_sub(SHARED, Ordering::Release);
    }

    // Safe wrapper: callable from fully safe code, with no lifetime tie
    // to any guard, so it can run while a shared guard is still alive.
    pub fn force_unlock_shared(&self) {
        unsafe { self.unlock_shared() }
    }
}

pub struct SharedMutex<T> {
    raw: RawLock,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send + Sync> Sync for SharedMutex<T> {}

pub struct SharedGuard<'a, T> {
    lock: &'a SharedMutex<T>,
}

impl<'a, T> Deref for SharedGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> Drop for SharedGuard<'a, T> {
    fn drop(&mut self) {
        self.lock.raw.force_unlock_shared();
    }
}

pub struct ExclusiveGuard<'a, T> {
    lock: &'a SharedMutex<T>,
}

impl<'a, T> Deref for ExclusiveGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> DerefMut for ExclusiveGuard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.lock.data.get() }
    }
}

impl<'a, T> Drop for ExclusiveGuard<'a, T> {
    fn drop(&mut self) {
        self.lock.raw.unlock_exclusive();
    }
}

impl<T> SharedMutex<T> {
    pub fn new(v: T) -> Self {
        SharedMutex { raw: RawLock::new(), data: UnsafeCell::new(v) }
    }

    pub fn try_lock_shared(&self) -> Option<SharedGuard<T>> {
        if self.raw.try_lock_shared() {
            Some(SharedGuard { lock: self })
        } else {
            None
        }
    }

    pub fn try_lock_exclusive(&self) -> Option<ExclusiveGuard<T>> {
        if self.raw.try_lock_exclusive() {
            Some(ExclusiveGuard { lock: self })
        } else {
            None
        }
    }

    // Public safe API: takes the guard by reference (not by value), so the
    // caller keeps using it after the shared slot has been released.
    pub fn force_unlock_shared(&self, _guard: &SharedGuard<T>) {
        self.raw.force_unlock_shared();
    }
}

