use std::hint;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;

use poc_lib::SharedMutex;

fn main() {
    let sm = Arc::new(SharedMutex::new(0i32));
    let sm2 = Arc::clone(&sm);
    let ready = Arc::new(AtomicBool::new(false));
    let ready2 = Arc::clone(&ready);

    let reader = thread::spawn(move || {
        let guard = sm2.try_lock_shared().unwrap();
        // Safe call: releases the shared slot while `guard` is still alive.
        sm2.force_unlock_shared(&guard);
        ready2.store(true, Ordering::Release);
        let mut sum = 0i32;
        for _ in 0..50_000_000 {
            sum = sum.wrapping_add(*guard); // unsynchronized read
        }
        hint::black_box(sum);
    });

    while !ready.load(Ordering::Acquire) {
        hint::spin_loop();
    }

    // The shared count was force-decremented to 0, so this exclusive lock
    // is wrongly granted while `reader` is still reading the same data.
    if let Some(mut wguard) = sm.try_lock_exclusive() {
        *wguard = 42; // unsynchronized write, concurrent with reader's reads
    }

    reader.join().unwrap();
}

