use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicUsize, Ordering};

const WRITER_BIT: usize = 1;

pub struct RawLock {
    state: AtomicUsize,
}

impl RawLock {
    pub const fn new() -> Self {
        RawLock { state: AtomicUsize::new(0) }
    }

    // Safe: spins until it wins the compare_exchange.
    pub fn lock_exclusive(&self) {
        loop {
            if self
                .state
                .compare_exchange(0, WRITER_BIT, Ordering::Acquire, Ordering::Relaxed)
                .is_ok()
            {
                return;
            }
            std::thread::yield_now();
        }
    }

    // Target function (kept semantically identical to parking_lot_rt).
    // Marked `unsafe fn` because it does not verify the caller owns the lock.
    #[inline]
    pub unsafe fn unlock_exclusive(&self) {
        // deadlock_release() omitted: not relevant to the race, no-op here.
        if self
            .state
            .compare_exchange(WRITER_BIT, 0, Ordering::Release, Ordering::Relaxed)
            .is_ok()
        {
            return;
        }
        // slow path omitted for minimality; state is always WRITER_BIT here in this PoC
    }

    // The unsound *safe* wrapper real parking_lot exposes as `force_unlock_write`.
    // It calls the unsafe primitive without any proof of ownership.
    pub fn force_unlock_exclusive(&self) {
        unsafe { self.unlock_exclusive() }
    }
}

unsafe impl Sync for RawLock {}

pub struct Cell {
    raw: RawLock,
    data: UnsafeCell<i32>,
}

unsafe impl Sync for Cell {}

impl Cell {
    pub fn new(v: i32) -> Self {
        Cell { raw: RawLock::new(), data: UnsafeCell::new(v) }
    }

    // Safe API: acquire exclusive access and get a raw pointer to write through.
    // (No guard type needed for this minimal PoC; the race is the point.)
    pub fn lock_exclusive(&self) -> *mut i32 {
        self.raw.lock_exclusive();
        self.data.get()
    }

    pub fn force_unlock_exclusive(&self) {
        self.raw.force_unlock_exclusive();
    }
}

