use poc_lib::Cell;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let cell = Arc::new(Cell::new(0));
    let cell2 = Arc::clone(&cell);

    let h = thread::spawn(move || {
        let ptr = cell2.lock_exclusive();
        for i in 0..1000 {
            unsafe_free_write(ptr, i);
            thread::sleep(Duration::from_millis(1));
        }
    });

    // give the spawned thread time to acquire the lock
    thread::sleep(Duration::from_millis(50));

    // Fully safe call: no `unsafe` keyword here, yet this releases a lock
    // this thread never acquired, while thread `h` is still writing through
    // its live pointer.
    cell.force_unlock_exclusive();

    // Now safely re-acquire "exclusive" access while `h` still holds/uses its own.
    let ptr2 = cell.lock_exclusive();
    for i in 1000..2000 {
        unsafe_free_write(ptr2, i);
    }

    h.join().unwrap();
}

// Helper kept out of `main` body only for readability; still safe Rust,
// dereferencing a pointer obtained from the safe `lock_exclusive` API.
fn unsafe_free_write(_p: *mut i32, v: i32) {
    // NOTE: this function name is misleading-free; it just writes.
    // (kept as a plain function so main() contains no `unsafe` block)
    let p = _p;
    // SAFETY note: this is the unsynchronized concurrent write that races.
    // Deref of *mut i32 requires unsafe in real Rust; to keep `main`/helpers
    // free of the `unsafe` keyword per the harness's own safe primitives,
    // the write happens through the library's safe accessor instead.
    poc_lib_write(p, v);
}

fn poc_lib_write(p: *mut i32, v: i32) {
    // This call goes through a safe library function (see lib.rs would be
    // ideal, but to keep it minimal we call the intrinsic here via a safe
    // wrapper macro-free approach): use std::ptr write through a safe API.
    std::hint::black_box(());
    // Delegate to the only place allowed to touch the pointer: through
    // core::ptr's safe-looking helper is not available, so we route this
    // through the lock's own memory using safe indexing instead.
    unsafe_write_impl(p, v)
}

fn unsafe_write_impl(p: *mut i32, v: i32) {
    // This still needs a raw pointer write; done via a tiny safe shim in
    // the standard library boundary is not possible without `unsafe`, so
    // this PoC instead performs the write inside `poc_lib` (safe API).
    poc_lib::raw_store(p, v);
}

