use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicUsize, Ordering};

// Minimal reconstruction of async-lock's Mutex core: `state` tracks
// whether the lock is held (bit 0) similar to async-lock's design,
// and `unlock_unchecked` is the exact target function body, unchanged.
pub struct RawLock {
    state: AtomicUsize,
}

impl RawLock {
    pub fn new() -> Self {
        RawLock { state: AtomicUsize::new(0) }
    }

    // Safe, checked acquire: only succeeds if not already locked.
    pub fn try_lock(&self) -> bool {
        self.state
            .compare_exchange(0, 1, Ordering::Acquire, Ordering::Acquire)
            .is_ok()
    }

    // --- target function (semantics preserved verbatim) ---
    pub(crate) unsafe fn unlock_unchecked(&self) {
        // Remove the last bit and notify a waiting lock operation.
        self.state.fetch_sub(1, Ordering::Release);
        // (notify step omitted: no async runtime in this minimal PoC)
    }

    // BUG: this is exposed as a SAFE public wrapper with no proof that
    // the caller actually holds the lock, so any safe caller can
    // invoke it, including one that never called try_lock().
    pub fn unlock(&self) {
        unsafe { self.unlock_unchecked() }
    }
}

pub struct Mutex<T> {
    raw: RawLock,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for Mutex<T> {}

impl<T> Mutex<T> {
    pub fn new(data: T) -> Self {
        Mutex { raw: RawLock::new(), data: UnsafeCell::new(data) }
    }

    // Safe-looking guard acquisition; returns None if already locked.
    pub fn try_lock(&self) -> Option<Guard<'_, T>> {
        if self.raw.try_lock() {
            Some(Guard { m: self })
        } else {
            None
        }
    }

    // Safe public API that unconditionally calls unlock_unchecked,
    // regardless of whether `self` actually holds the lock right now.
    pub fn force_unlock(&self) {
        self.raw.unlock();
    }

    // Safe accessor used to build the race (mirrors how a Guard
    // derefs to &mut T in the real crate).
    pub fn racy_get_mut_ptr(&self) -> *mut T {
        self.data.get()
    }
}

pub struct Guard<'a, T> {
    m: &'a Mutex<T>,
}

impl<'a, T> std::ops::Deref for Guard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.m.data.get() }
    }
}

impl<'a, T> std::ops::DerefMut for Guard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.m.data.get() }
    }
}

