use std::marker::PhantomData;

pub struct RawSlice<T> {
    ptr: *const T,
    #[cfg(debug_assertions)]
    end: *const T,
    _spooky: PhantomData<T>,
}

impl<T> RawSlice<T> {
    /// SAFETY: caller must ensure `len` elements starting at `ptr` are valid for reads.
    pub unsafe fn from_raw_parts(ptr: *const T, len: usize) -> Self {
        let _ = len;
        Self {
            ptr,
            #[cfg(debug_assertions)]
            end: ptr.wrapping_add(len),
            _spooky: PhantomData,
        }
    }

    // Safe public constructor: decodes a "logical length" (e.g. from a length-prefixed
    // wire format) and hands it straight to from_raw_parts without checking it against
    // the backing Vec's actual length/capacity.
    pub fn from_vec_with_len(v: &Vec<T>, len: usize) -> Self {
        unsafe { Self::from_raw_parts(v.as_ptr(), len) }
    }

    // Safe-looking accessor that relies on `end` (when present) as the bounds invariant.
    // Because `end` was derived from the untrusted `len`, this check is worthless when
    // `len` was wrong to begin with.
    pub fn get(&self, index: usize) -> &T {
        #[cfg(debug_assertions)]
        {
            let cap = (self.end as usize - self.ptr as usize) / std::mem::size_of::<T>();
            assert!(index < cap, "index out of logical bounds");
        }
        unsafe { &*self.ptr.add(index) }
    }
}

