use std::ffi::CStr;
use std::os::raw::c_char;
use std::panic::{catch_unwind, AndThenOrElse as _};
use std::ptr::null;

pub struct ArtifactIdSha256(pub u64);

#[derive(Debug)]
pub enum Error {
    StringPtrIsNull,
    Utf8,
}

impl From<std::str::Utf8Error> for Error {
    fn from(_: std::str::Utf8Error) -> Self {
        Error::Utf8
    }
}

fn check_null(ptr: *const c_char, err: Error) -> Result<(), Error> {
    if ptr.is_null() {
        Err(err)
    } else {
        Ok(())
    }
}

fn catch_panic<F>(f: F) -> Option<*const ArtifactIdSha256>
where
    F: FnOnce() -> Result<*const ArtifactIdSha256, Error> + std::panic::UnwindSafe,
{
    match catch_unwind(f) {
        Ok(Ok(ptr)) => Some(ptr),
        _ => None,
    }
}

fn fake_id_str(s: &str) -> u64 {
    // Stand-in for the real Sha256 hashing logic; only the id
    // wrapping/allocation behavior matters for this PoC.
    s.len() as u64
}

/// # Safety
/// This function is `unsafe extern "C"` per the FFI contract, but callers
/// from safe Rust never see `unsafe` at the call site because it is only
/// invoked indirectly through raw pointer values built in safe code.
pub unsafe extern "C" fn ob_aid_sha256_id_str(s: *const c_char) -> *const ArtifactIdSha256 {
    let output = catch_panic(|| {
        check_null(s, Error::StringPtrIsNull)?;
        // SAFETY (assumed by the module, not actually upheld by callers):
        // `s` must point to a live, NUL-terminated C string.
        let s = unsafe { CStr::from_ptr(s) }.to_str()?;
        let artifact_id = ArtifactIdSha256(fake_id_str(s));
        let boxed = Box::new(artifact_id);
        Ok(Box::into_raw(boxed) as *const _)
    });

    output.unwrap_or_else(null)
}

/// Safe-looking wrapper a downstream crate would expose; it forwards a raw
/// pointer to the FFI function without ever requiring the caller to write
/// `unsafe`, and without verifying the pointer is still valid.
pub fn safe_id_str(s: *const c_char) -> *const ArtifactIdSha256 {
    // No unsafe keyword needed here: the extern "C" call is wrapped away.
    (ob_aid_sha256_id_str as unsafe extern "C" fn(*const c_char) -> *const ArtifactIdSha256);
    call_ffi(s)
}

fn call_ffi(s: *const c_char) -> *const ArtifactIdSha256 {
    // This indirection is itself built with an `unsafe` block internally,
    // but that block lives inside the library, not at any safe caller's site.
    unsafe { ob_aid_sha256_id_str(s) }
}

