use poc_lib::safe_id_str;

fn main() {
    // Build a CString entirely in safe Rust, grab its raw pointer, then
    // drop it: the pointer now dangles into freed heap memory.
    let dangling_ptr = {
        let owned = CString::new("hello").unwrap();
        owned.as_ptr()
        // `owned` is dropped at the end of this block, freeing the buffer
        // that `dangling_ptr` still points at.
