    // Safe Rust call: no `unsafe` keyword anywhere in this file.
    // The library's public API accepts a raw pointer and forwards it into
    // the FFI function, which dereferences it via CStr::from_ptr, reading
    // freed memory -- UB, detected by Miri as use-after-free.
    let result_ptr = safe_id_str(dangling_ptr);

