use std::ffi::{c_char, c_void, CStr, CString};

#[derive(Clone, Copy)]
pub enum IncludeType {
    Local,
    System,
}

pub struct IncludeResult {
    pub name: String,
    pub data: String,
}

/// Mirrors glslang-rs's `IncludeCallback` alias.
pub type IncludeCallback = fn(IncludeType, &str, &str, usize) -> Option<IncludeResult>;

#[repr(C)]
pub struct glsl_include_result_t {
    pub header_name: *mut c_char,
    pub header_data: *mut c_char,
    pub header_length: usize,
}

/// Reconstruction of glslang-rs's `_glslang_rs_call_func` trampoline.
unsafe fn _glslang_rs_call_func(
    ctx: *mut c_void,
    ty: IncludeType,
    header_name: *const c_char,
    includer_name: *const c_char,
    include_depth: usize,
) -> *mut glsl_include_result_t {
    let Ok(s) = std::panic::catch_unwind(|| unsafe {
        let Some(callback) = ctx.cast_const().cast::<IncludeCallback>().as_ref() else {
            return core::ptr::null_mut();
        };

        let header_name = CStr::from_ptr(header_name);
        let includer_name = CStr::from_ptr(includer_name);

        let (Ok(header_name), Ok(includer_name)) = (header_name.to_str(), includer_name.to_str())
        else {
            return core::ptr::null_mut();
        };

        let Some(result) = callback(ty, header_name, includer_name, include_depth) else {
            return core::ptr::null_mut();
        };

        let header_data_len = result.data.len();

        // SAFETY: String has no internal nulls.
        let header_name_leaked = CString::new(result.name).unwrap().into_raw();
        let header_data_leaked = CString::new(result.data).unwrap().into_raw();

        return Box::into_raw(Box::new(glsl_include_result_t {
            header_name: header_name_leaked,
            header_data: header_data_leaked,
            header_length: header_data_len,
        }));
    }) else {
        return core::ptr::null_mut();
    };

    s
}

/// Safe public wrapper, analogous to the crate's includer registration API.
pub struct Includer {
    ctx: *mut c_void,
}

impl Includer {
    // No `unsafe` keyword: looks like an ordinary safe constructor, but it
    // stashes the address of the borrowed callback without any lifetime tie
    // to `Self`, so the borrow checker cannot stop the pointee from dying
    // before `resolve` is called.
    pub fn new(callback: &IncludeCallback) -> Self {
        Includer {
            ctx: callback as *const IncludeCallback as *mut c_void,
        }
    }

    pub fn resolve(
        &self,
        ty: IncludeType,
        header_name: &str,
        includer_name: &str,
        depth: usize,
    ) -> Option<String> {
        let header_name_c = CString::new(header_name).unwrap();
        let includer_name_c = CString::new(includer_name).unwrap();

        let result_ptr = unsafe {
            _glslang_rs_call_func(
                self.ctx,
                ty,
                header_name_c.as_ptr(),
                includer_name_c.as_ptr(),
                depth,
            )
        };

        if result_ptr.is_null() {
            return None;
        }

        let result = unsafe { Box::from_raw(result_ptr) };
        let data = unsafe { CStr::from_ptr(result.header_data) }
            .to_string_lossy()
            .into_owned();
        Some(data)
    }
}

