fn my_callback(
    _ty: IncludeType,
    _header: &str,
    _includer: &str,
    _depth: usize,
) -> Option<IncludeResult> {
    Some(IncludeResult {
        name: "foo.glsl".to_string(),
        data: "// injected header".to_string(),
    })
}

// Fully safe helper: builds an `Includer` from a callback that lives only
// on this function's stack frame, then hands the (now dangling-capable)
// `Includer` back to the caller. No `unsafe` appears anywhere here.
fn make_includer() -> Includer {
    let callback: fn(IncludeType, &str, &str, usize) -> Option<IncludeResult> = my_callback;
    Includer::new(&callback)
}

fn main() {
    let includer = make_includer();
    // The stack slot that held `callback` in `make_includer` has been
    // deallocated by now; this call makes the FFI trampoline materialize a
    // reference to freed stack memory and invoke through it.
    let _ = includer.resolve(IncludeType::Local, "foo.glsl", "main.glsl", 0);
}

