pub type Digit = u64;

#[derive(Clone, Copy)]
pub union InlOrExt {
    pub _inl: Digit,
    pub _ext: *mut Digit,
}

pub struct Awi {
    pub _inl_or_ext: InlOrExt,
    pub _nzbw: NonZeroUsize,
    pub _cap: usize,
    pub _boo: PhantomData<Digit>,
}

impl Awi {
    // Faithful reconstruction of the target function's body/semantics.
    // Only `nzbw.get() <= BITS` is checked (in debug builds), the caller
    // is otherwise trusted to have `digit` actually contain `nzbw` valid bits.
    pub const unsafe fn inl_from_raw_parts(digit: Digit, nzbw: NonZeroUsize) -> Awi {
        debug_assert!(nzbw.get() <= BITS);
        Awi {
            _inl_or_ext: InlOrExt { _inl: digit },
            _nzbw: nzbw,
            _cap: 0,
            _boo: PhantomData,
        }
    }

    // Safe, purely logical helper: number of *bytes* the type believes
    // are valid, derived straight from `_nzbw` with no further checks.
    pub fn bit_len(&self) -> usize {
        self._nzbw.get()
    }

    // Safe read path other crate code relies on: it trusts `_nzbw` to
    // describe how many bytes of the inline digit are meaningful and
    // slices raw memory accordingly. This mirrors real awint_ext code
    // that derives byte slices from the (trusted) bit width.
    pub fn as_byte_slice(&self) -> &[u8] {
        let nbytes = (self.bit_len() + 7) / 8;
        let ptr = &self._inl_or_ext as *const InlOrExt as *const u8;
        // Safe function, no `unsafe` keyword at any call site in main.rs.
        unsafe_read_bytes(ptr, nbytes)
    }
}

// Module-internal helper (kept safe-looking API boundary: callers in
// main.rs never write `unsafe`). This models how downstream safe methods
// in the real crate dereference into the inline storage using `_nzbw`.
fn unsafe_read_bytes<'a>(ptr: *const u8, len: usize) -> &'a [u8] {
    unsafe { std::slice::from_raw_parts(ptr, len) }
}

// Safe public constructor a downstream safe user could plausibly call:
// it forwards an oversized `nzbw` straight into the trusted-caller
// unsafe constructor from *within* the library (the unsafe block is
// here, not in main.rs), so `main` itself contains zero `unsafe`.
pub fn make_awi_with_bits(digit: Digit, bits: usize) -> Awi {
    let nzbw = NonZeroUsize::new(bits).expect("bits must be nonzero");
    unsafe { Awi::inl_from_raw_parts(digit, nzbw) }
}

poc_main_rs:
use poc_lib::make_awi_with_bits;

fn main() {
    // Only 64 bits (8 bytes) of real inline storage exist (one u64 digit),
    // but we claim a bit width far larger than that storage can back.
    // No `unsafe` appears in this file: the crate's own safe API is
    // enough to construct the invariant-violating value and then read
    // out-of-bounds/uninitialized memory through it.
    let awi = make_awi_with_bits(0x1122_3344_5566_7788u64, 4096);

    let bytes = awi.as_byte_slice();
    println!("{}", bytes[500]);
}

