use std::ptr;

pub type ComponentId = usize;

pub trait Component: 'static {}

pub trait Bundle {
    fn component_ids() -> Vec<ComponentId>;
    fn get_components(self, func: &mut impl FnMut(*mut u8));
}

// bevy_ecs implements `Bundle` for tuples via a blanket macro, so a tuple
// of two fields of the *same* component type, like (A, A), is an entirely
// ordinary, safe-to-construct Bundle from a caller's perspective.
impl<A: Component> Bundle for (A, A) {
    fn component_ids() -> Vec<ComponentId> {
        // both tuple fields are the same component type -> same id twice
        vec![0, 0]
    }

    fn get_components(self, func: &mut impl FnMut(*mut u8)) {
        let (mut a0, mut a1) = self;
        func(&mut a0 as *mut A as *mut u8);
        std::mem::forget(a0);
        func(&mut a1 as *mut A as *mut u8);
        std::mem::forget(a1);
    }
}

/// Mirrors bevy_ecs's BundleInfo construction: component ids are
/// deduplicated so each Table column is only created once. Nothing here
/// checks that the Bundle's `get_components` call count (which is NOT
/// deduplicated: (A, A) still invokes the closure twice) matches the
/// deduplicated id count. `shrink_to_fit` makes the mismatch land outside
/// the actual heap allocation, so Miri can observe the OOB read.
pub fn compute_deduped_component_ids<T: Bundle>() -> Vec<ComponentId> {
    let mut ids = T::component_ids();
    let mut seen = Vec::new();
    ids.retain(|id| {
        if seen.contains(id) {
            false
        } else {
            seen.push(*id);
            true
        }
    });
    ids.shrink_to_fit();
    ids
}

pub struct Column {
    data: Vec<u8>,
    item_size: usize,
}

impl Column {
    pub fn with_capacity(item_size: usize, rows: usize) -> Self {
        Column { data: vec![0u8; item_size * rows], item_size }
    }

    pub unsafe fn initialize(&mut self, row: usize, component_ptr: *mut u8) {
        let dst = self.data.as_mut_ptr().add(row * self.item_size);
        ptr::copy_nonoverlapping(component_ptr, dst, self.item_size);
    }
}

pub struct Table {
    columns: Vec<(ComponentId, Column)>,
}

impl Table {
    pub fn new(component_id: ComponentId, item_size: usize, rows: usize) -> Self {
        Table { columns: vec![(component_id, Column::with_capacity(item_size, rows))] }
    }

    pub fn get_column_mut(&mut self, component_id: ComponentId) -> Option<&mut Column> {
        self.columns.iter_mut().find(|(id, _)| *id == component_id).map(|(_, c)| c)
    }
}

pub struct BundleInserter {
    pub component_ids: Vec<ComponentId>,
}

impl BundleInserter {
    // Root-cause reproduction of bevy_ecs's `write_components`
    // (crates/bevy_ecs/src/bundle.rs): `bundle_component` indexes
    // `component_ids` with `get_unchecked` for every field the Bundle
    // yields via `get_components`, but nothing validates that the
    // Bundle's field count matches `component_ids.len()`.
    pub fn write_components<T: Bundle>(&self, table: &mut Table, table_row: usize, bundle: T) {
        let mut bundle_component = 0;
        bundle.get_components(&mut |component_ptr| {
            // SAFETY (assumed by the original code, never actually checked):
            // "bundle_component is a valid index for this bundle"
            let component_id = unsafe { *self.component_ids.get_unchecked(bundle_component) };
            let column = table.get_column_mut(component_id).unwrap();
            unsafe { column.initialize(table_row, component_ptr) };
            bundle_component += 1;
        });
    }
}

poc_main_rs:
use poc_lib::{compute_deduped_component_ids, BundleInserter, Component, Table};

struct A(u64);
impl Component for A {}

fn main() {
    // (A, A) is a perfectly ordinary, 100% safe Rust bundle value: two
    // fields of the same component type. No `unsafe` appears anywhere
    // in this function.
    let component_ids = compute_deduped_component_ids::<(A, A)>();
    assert_eq!(component_ids.len(), 1); // deduplicated down to 1 real column

    let mut table = Table::new(component_ids[0], std::mem::size_of::<A>(), 1);
    let inserter = BundleInserter { component_ids };

    // get_components() invokes the closure twice (once per tuple field),
    // but component_ids has only 1 entry with capacity shrunk to 1, so the
    // second iteration's get_unchecked(1) reads one usize past the end of
    // that heap allocation -> undefined behavior, triggered purely by safe
    // Rust composing the public API.
    inserter.write_components(&mut table, 0, (A(1), A(2)));
}

