use std::ptr;

// Mirrors imxrt1062-adc1's register writer proxy `W` and field-setter builder.
pub struct W {
    pub bits: u32,
    // Points at the (simulated) memory-mapped ADC register this W will flush to.
    pub reg: *mut u32,
}

impl W {
    // Commits the staged bits to the device register (models the real `write` finalizer).
    pub fn write_to_device(&mut self) {
        unsafe { ptr::write_volatile(self.reg, self.bits) }
    }
}

pub struct FieldWriter<'a> {
    pub w: &'a mut W,
}

impl<'a> FieldWriter<'a> {
    // Same body/semantics as the real imxrt1062-adc1 `bits()`: masks to the 5-bit
    // field width and OR's the raw value in with NO check that it's a valid encoding.
    pub unsafe fn bits(self, value: u8) -> &'a mut W {
        self.w.bits = (self.w.bits & !0x1f) | ((value as u32) & 0x1f);
        self.w
    }
}

// Safe wrapper of the kind svd2rust / downstream HAL crates commonly generate:
// it calls the `unsafe fn bits` internally but exposes a totally safe API surface,
// so callers never need (and never write) the `unsafe` keyword themselves.
pub struct SafeAdcField<'a> {
    pub w: &'a mut W,
}

impl<'a> SafeAdcField<'a> {
    pub fn set_bits(self, value: u8) -> &'a mut W {
        let fw = FieldWriter { w: self.w };
        // SAFETY (claimed by wrapper author, not actually enforced): value is
        // assumed to be a valid 5-bit ADC field encoding. No check is performed.
        unsafe { fw.bits(value) }
    }
}

poc_main_rs:
use poc::{SafeAdcField, W};

fn main() {
    // Simulate an ADC register at an address with no real device backing it
    // (no hardware mapped in this process) -> writing here is a wild MMIO write.
    let reg_addr = 0x4000_0000usize as *mut u32;

    let mut w = W { bits: 0, reg: reg_addr };

    // Purely safe Rust: no `unsafe` keyword appears here, yet an out-of-range
    // field value (0xFF masked to 0x1f is still an undefined ADC channel/gain
    // encoding) is forwarded straight to the device register.
    let field = SafeAdcField { w: &mut w };
    let w_ref = field.set_bits(0xFF);
    w_ref.write_to_device();
}

