use std::marker::PhantomData;
use std::ptr;

// Minimal stand-in for svd2rust's register-width trait (REG::Ux)
pub trait RegisterSpec {
    type Ux: Copy;
}

pub struct MyReg;
impl RegisterSpec for MyReg {
    type Ux = u32;
}

// Minimal stand-in for the svd2rust `W` write-proxy tied to a register instance
pub struct W<REG: RegisterSpec> {
    pub bits: REG::Ux,
    pub addr: *mut REG::Ux,
    _marker: PhantomData<REG>,
}

impl<REG: RegisterSpec> W<REG> {
    pub fn new(addr: *mut REG::Ux, initial: REG::Ux) -> Self {
        W { bits: initial, addr, _marker: PhantomData }
    }

    // Faithful reconstruction of the target function's body semantics:
    // it blindly stores whatever raw value the caller passes, with no
    // validation that `bits` is a legal encoding for the field/register.
    pub unsafe fn bits(&mut self, bits: REG::Ux) -> &mut Self {
        self.bits = bits;
        self
    }

    // Safe wrapper mirroring how svd2rust register modules expose `bits()`
    // as reachable through a safe `write` closure API, without requiring
    // the caller to write `unsafe` at the call site.
    pub fn write_bits_safely(&mut self, value: REG::Ux) -> &mut Self {
        // SAFETY (claimed by the module, not actually upheld): the module
        // assumes callers only ever pass validated field encodings, but
        // nothing here enforces that invariant.
        unsafe { self.bits(value) };
        // Commit the raw value straight to the "device" register.
        unsafe { ptr::write_volatile(self.addr, self.bits) };
        self
    }
}

poc_main_rs:
use poc_lib::{MyReg, W};

fn main() {
    // No real hardware mapped: this stands in for an MMIO register address
    // that is not backed by valid memory, mirroring an unmapped device register.
    let bogus_addr = 0x2000_usize as *mut u32;

    let mut w: W<MyReg> = W::new(bogus_addr, 0);

    // Fully safe call site: no `unsafe` keyword here, yet an arbitrary,
    // unvalidated raw value (0xFFFF_FFFF) is forwarded straight into the
    // register write, exactly like composing safe accessors around
    // svd2rust's `bits()` setter.
    w.write_bits_safely(0xFFFF_FFFF);
}

