// Minimal reconstruction of addr-spec's EmailAddress core.
// `literal` records whether `domain` is a bracketed literal like "[127.0.0.1]".
// Internal code trusts this flag and uses it to skip the brackets via raw slicing
// without re-checking that the brackets actually exist / are in range.
pub struct EmailAddress {
    local_part: String,
    domain: String,
    literal: bool,
}

impl EmailAddress {
    // Safe-looking public constructor: NO validation that `literal` actually
    // matches the syntactic shape of `domain` (missing precondition check).
    pub fn new_unchecked(local_part: String, domain: String, literal: bool) -> Self {
        unsafe { Self::new_unchecked_impl(local_part, domain, literal) }
    }

    // This is the target function (kept verbatim in spirit): it just stores
    // fields, trusting the caller validated `literal` vs `domain` beforehand.
    unsafe fn new_unchecked_impl(local_part: String, domain: String, literal: bool) -> Self {
        Self {
            local_part,
            domain,
            literal,
        }
    }

    // Downstream logic trusts `literal`: if true, it assumes `domain` is at
    // least 2 bytes long and wrapped in '[' ']', so it slices off exactly one
    // byte from each end via unchecked pointer arithmetic (as real crates do
    // for performance in "trusted invariant" internal helpers).
    pub fn domain_host(&self) -> &str {
        if self.literal {
            let bytes = self.domain.as_bytes();
            // SAFETY (assumed, not checked): literal domains are always
            // "[...]" with len >= 2, guaranteed by construction.
            unsafe {
                let ptr = bytes.as_ptr().add(1);
                let len = bytes.len() - 2; // underflows / OOB if domain is short
                let slice = std::slice::from_raw_parts(ptr, len);
                std::str::from_utf8_unchecked(slice)
            }
        } else {
            &self.domain
        }
    }
}

poc_main_rs:
fn main() {
    // Fully safe call site: no `unsafe` keyword here.
    // We claim `literal = true` but supply a domain that is NOT a
    // bracketed literal (too short / no brackets) — the constructor
    // never checks this precondition.
    let addr = poc_lib::EmailAddress::new_unchecked(
        "user".to_string(),
        "a".to_string(), // len == 1, not "[..]"
        true,
    );

    // Triggers out-of-bounds pointer arithmetic / slice construction (UB).
    let host = addr.domain_host();
    println!("{}", host);
}
